   621→    VALUES ($1, $2, $3, 'dynamic', $4, $5, 100, $6, $7, $8,
   622→            EXTRACT(EPOCH FROM (NOW() - $9::timestamp)), $9, NOW())
   623→    RETURNING id
   624→  `, [
   625→    userId,
