          edu.degree,
          edu.field,
          edu.start_date ? new Date(edu.start_date + '-01-01') : null,
          edu.end_date && edu.end_date !== 'Present' ? new Date(edu.end_date + '-01-01') : null,
          edu.gpa,
          JSON.stringify(edu.achievements || []),
          i
        ]);
      }
