                  {aiSummaryLoading ? 'Analyzing...' : aiSummary ? 'Refresh' : 'Generate Summary'}
                </Button>
              </div>
              {aiSummaryLoading && (
                <div className="flex items-center gap-2 text-sm text-primary py-4 justify-center">
                  <Loader2 className="h-4 w-4 animate-spin" />
